cases.sql_query:
SELECT COUNT(*) AS movie_count
FROM movies
WHERE Distributor = 'Warner Bros.';

SELECT COUNT(*) AS days_count
FROM seattle_weather
WHERE temp_max > 30;

SELECT COUNT(*) AS trip_count
FROM nyc_taxi
WHERE payment_type = 1;

SELECT 100.0 * COUNT(CASE WHEN order_count > 1 THEN 1 END) / COUNT(*) AS pct_repeat_customers
FROM (
  SELECT customer_unique_id, COUNT(*) AS order_count
  FROM olist_customers
  GROUP BY customer_unique_id
);
